import{_ as a,o as e,c as l,a3 as i}from"./chunks/framework.DACwFHq9.js";const b=JSON.parse('{"title":"移动端概览","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/mobile/index.md","filePath":"user-guide/mobile/index.md","lastUpdated":1781934556000}'),r={name:"user-guide/mobile/index.md"};function d(o,t,n,h,s,u){return e(),l("div",null,[...t[0]||(t[0]=[i('<h1 id="移动端概览" tabindex="-1">移动端概览 <a class="header-anchor" href="#移动端概览" aria-label="Permalink to &quot;移动端概览&quot;">​</a></h1><p>AIO Hub Mobile 是面向手机和平板的移动端实现，基于 Tauri v2 和 Vue 3 构建。移动端不会完整复制桌面端的所有工具，而是优先提供适合触屏使用的核心能力。</p><h2 id="当前可用模块" tabindex="-1">当前可用模块 <a class="header-anchor" href="#当前可用模块" aria-label="Permalink to &quot;当前可用模块&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">模块</th><th style="text-align:left;">用途</th></tr></thead><tbody><tr><td style="text-align:left;">LLM 对话</td><td style="text-align:left;">新建会话、继续历史会话、发送消息、查看分支</td></tr><tr><td style="text-align:left;">LLM 服务</td><td style="text-align:left;">管理渠道、模型、Key 和自定义端点</td></tr><tr><td style="text-align:left;">日志管理</td><td style="text-align:left;">查看、搜索、过滤、导出运行日志</td></tr><tr><td style="text-align:left;">UI 测试</td><td style="text-align:left;">用于开发验证移动端组件效果</td></tr></tbody></table><p>移动端功能仍在持续对齐桌面端。遇到桌面端教程中没有出现在移动端的按钮或工具时，以移动端实际界面为准。</p><h2 id="首次使用" tabindex="-1">首次使用 <a class="header-anchor" href="#首次使用" aria-label="Permalink to &quot;首次使用&quot;">​</a></h2><ol><li>打开移动端应用。</li><li>在首页工具网格中进入「LLM 服务」。</li><li>新增一个服务渠道，填写 API Key 和模型。</li><li>回到首页，进入「AI 对话」。</li><li>点击「开启新对话」，发送第一条消息。</li></ol><p>如果你已经熟悉桌面端，可以把移动端理解为更轻量的随身对话面板：配置服务、发起会话、查看日志是目前最稳定的主线。</p><h2 id="界面结构" tabindex="-1">界面结构 <a class="header-anchor" href="#界面结构" aria-label="Permalink to &quot;界面结构&quot;">​</a></h2><p>移动端采用底部导航和触屏卡片布局：</p><ul><li>首页：展示已注册工具。</li><li>设置：主题、外观和应用级设置。</li><li>工具页：每个工具有独立路由和顶部栏。</li><li>弹层：模型选择、渠道编辑等复杂表单使用底部弹层或全屏编辑体验。</li></ul><p>移动端会处理安全区和键盘避让。输入时底部操作栏会贴近键盘，减少被遮挡的情况。</p><h2 id="与桌面端的差异" tabindex="-1">与桌面端的差异 <a class="header-anchor" href="#与桌面端的差异" aria-label="Permalink to &quot;与桌面端的差异&quot;">​</a></h2><ul><li>移动端更强调单任务流程，不提供桌面端的多窗口分离。</li><li>部分工具尚未移植。</li><li>UI 骨架由移动端自研 Vue 组件和 AIO Hub 主题 token 主导；Varlet 仅作为底层组件库按需使用。</li><li>移动端源码采用独立许可，发布和二次分发限制与桌面端不同。</li><li>路由和语言包单独维护，工具名称可能与桌面端略有差异。</li></ul><h2 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to &quot;使用建议&quot;">​</a></h2><ul><li>先在「LLM 服务」配置好至少一个可用渠道。</li><li>长文本编辑建议分段发送，避免移动键盘操作压力过大。</li><li>出现异常时，优先查看「日志管理」。</li><li>如果模型列表为空，可以手动添加模型，或通过渠道编辑器获取模型。</li><li>移动网络不稳定时，适当降低并发或切换更稳定的服务端点。</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="移动端支持全部桌面工具吗" tabindex="-1">移动端支持全部桌面工具吗？ <a class="header-anchor" href="#移动端支持全部桌面工具吗" aria-label="Permalink to &quot;移动端支持全部桌面工具吗？&quot;">​</a></h3><p>暂不支持。移动端当前优先覆盖 AI 对话、LLM 服务配置和日志查看等核心流程。</p><h3 id="移动端和桌面端数据会自动同步吗" tabindex="-1">移动端和桌面端数据会自动同步吗？ <a class="header-anchor" href="#移动端和桌面端数据会自动同步吗" aria-label="Permalink to &quot;移动端和桌面端数据会自动同步吗？&quot;">​</a></h3><p>当前教程不假设自动同步。请以移动端本地配置为准；跨端同步能力如果后续加入，会在对应页面说明。</p><h3 id="为什么某些教程截图和移动端不一样" tabindex="-1">为什么某些教程截图和移动端不一样？ <a class="header-anchor" href="#为什么某些教程截图和移动端不一样" aria-label="Permalink to &quot;为什么某些教程截图和移动端不一样？&quot;">​</a></h3><p>大多数工具教程以桌面端为主。移动端使用单独布局，请优先参考移动端章节。</p><h3 id="移动端可以商用或二次分发吗" tabindex="-1">移动端可以商用或二次分发吗？ <a class="header-anchor" href="#移动端可以商用或二次分发吗" aria-label="Permalink to &quot;移动端可以商用或二次分发吗？&quot;">​</a></h3><p>移动端目录采用私有许可证，未获授权不得商用、二次分发或套壳发布。</p>',25)])])}const p=a(r,[["render",d]]);export{b as __pageData,p as default};
